99	      baseURL: baseURL ?? defaultBaseURL,
100	      headers: getHeaders,
101	      fetch: options.fetch,
102	    });
103	
104	  const createLanguageModel = (modelId: ProdiaLanguageModelId) =>
105	    new ProdiaLanguageModel(modelId, {
106	      provider: 'prodia.language',
107	      baseURL: baseURL ?? defaultBaseURL,
108	      headers: getHeaders,
