import type { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import type { InferSchema } from '@ai-sdk/provider-utils';
import {
  combineHeaders,
  lazySchema,
  parseJSON,
  parseProviderOptions,
  postToApi,
  resolve,
  zodSchema,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';
import type { ProdiaModelConfig } from './prodia-api';
import {
  buildProdiaProviderMetadata,
  parseMultipart,
  prodiaFailedResponseHandler,
  prodiaJobResultSchema,
} from './prodia-api';
import type { ProdiaJobResult } from './prodia-api';
import type { ProdiaImageModelId } from './prodia-image-settings';

export class ProdiaImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 1;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: ProdiaImageModelId,
    private readonly config: ProdiaModelConfig,
  ) {}

  private async getArgs({
    prompt,
    size,
    seed,
    providerOptions,
  }: Parameters<ImageModelV3['doGenerate']>[0]) {
    const warnings: Array<SharedV3Warning> = [];

    const prodiaOptions = await parseProviderOptions({
      provider: 'prodia',
      providerOptions,
      schema: prodiaImageModelOptionsSchema,
    });

    let width: number | undefined;
    let height: number | undefined;
    if (size) {
      const [widthStr, heightStr] = size.split('x');
      width = Number(widthStr);
      height = Number(heightStr);
      if (
        !widthStr ||
        !heightStr ||
        !Number.isFinite(width) ||
        !Number.isFinite(height)
      ) {
        warnings.push({
          type: 'unsupported',
          feature: 'size',
          details: `Invalid size format: ${size}. Expected format: WIDTHxHEIGHT (e.g., 1024x1024)`,
        });
        width = undefined;
        height = undefined;
      }
    }

    const jobConfig: Record<string, unknown> = {
      prompt,
    };

    if (prodiaOptions?.width !== undefined) {
      jobConfig.width = prodiaOptions.width;
    } else if (width !== undefined) {
      jobConfig.width = width;
    }

    if (prodiaOptions?.height !== undefined) {
      jobConfig.height = prodiaOptions.height;
    } else if (height !== undefined) {
      jobConfig.height = height;
    }

    if (seed !== undefined) {
      jobConfig.seed = seed;
    }
    if (prodiaOptions?.steps !== undefined) {
      jobConfig.steps = prodiaOptions.steps;
    }
    if (prodiaOptions?.stylePreset !== undefined) {
      jobConfig.style_preset = prodiaOptions.stylePreset;
    }
    if (prodiaOptions?.loras !== undefined && prodiaOptions.loras.length > 0) {
      jobConfig.loras = prodiaOptions.loras;
    }
    if (prodiaOptions?.progressive !== undefined) {
      jobConfig.progressive = prodiaOptions.progressive;
    }

    const body = {
      type: this.modelId,
      config: jobConfig,
    };

    return { body, warnings };
  }

  async doGenerate(
    options: Parameters<ImageModelV3['doGenerate']>[0],
  ): Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {
    const { body, warnings } = await this.getArgs(options);

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();
    const combinedHeaders = combineHeaders(
      await resolve(this.config.headers),
      options.headers,

import { JSONArray, JSONValue } from '../../json-value';
import { ImageModelV3Usage } from './image-model-v3-usage';
import { ImageModelV3CallOptions } from './image-model-v3-call-options';
import { SharedV3Warning } from '../../shared/v3/shared-v3-warning';

export type ImageModelV3ProviderMetadata = Record<
  string,
  {
    images: JSONArray;
  } & JSONValue
>;

type GetMaxImagesPerCallFunction = (options: {
  modelId: string;
}) => PromiseLike<number | undefined> | number | undefined;

/**
 * Image generation model specification version 3.
 */
export type ImageModelV3 = {
  /**
   * The image model must specify which image model interface
   * version it implements. This will allow us to evolve the image
   * model interface and retain backwards compatibility. The different
   * implementation versions can be handled as a discriminated union
   * on our side.
   */
  readonly specificationVersion: 'v3';

  /**
   * Name of the provider for logging purposes.
   */
  readonly provider: string;

  /**
   * Provider-specific model ID for logging purposes.
   */
  readonly modelId: string;

  /**
   * Limit of how many images can be generated in a single API call.
   * Can be set to a number for a fixed limit, to undefined to use
   * the global limit, or a function that returns a number or undefined,
   * optionally as a promise.
   */
  readonly maxImagesPerCall: number | undefined | GetMaxImagesPerCallFunction;

  /**
   * Generates an array of images.
   */
  doGenerate(options: ImageModelV3CallOptions): PromiseLike<{
    /**
     * Generated images as base64 encoded strings or binary data.
     * The images should be returned without any unnecessary conversion.
     * If the API returns base64 encoded strings, the images should be returned
     * as base64 encoded strings. If the API returns binary data, the images should
     * be returned as binary data.
     */
    images: Array<string> | Array<Uint8Array>;

    /**
     * Warnings for the call, e.g. unsupported features.
     */
    warnings: Array<SharedV3Warning>;

    /**
     * Additional provider-specific metadata. They are passed through
     * from the provider to the AI SDK and enable provider-specific
     * results that can be fully encapsulated in the provider.
     *
     * The outer record is keyed by the provider name, and the inner
     * record is provider-specific metadata. It always includes an
     * `images` key with image-specific metadata
     *
     * ```ts
     * {
     * "openai": {
     * "images": ["revisedPrompt": "Revised prompt here."]
     * }
     * }
     * ```
     */
    providerMetadata?: ImageModelV3ProviderMetadata;

    /**
     * Response information for telemetry and debugging purposes.
     */
    response: {
      /**
       * Timestamp for the start of the generated response.
       */
      timestamp: Date;

      /**
       * The ID of the response model that was used to generate the response.
       */
      modelId: string;

      /**
       * Response headers.
       */
      headers: Record<string, string> | undefined;
    };

    /**
     * Optional token usage for the image generation call (if the provider reports it).
     */
    usage?: ImageModelV3Usage;
  }>;
};

import { SharedV3ProviderOptions } from '../../shared';
import { ImageModelV3File } from './image-model-v3-file';

export type ImageModelV3CallOptions = {
  /**
   * Prompt for the image generation. Some operations, like upscaling, may not require a prompt.
   */
  prompt: string | undefined;

  /**
   * Number of images to generate.
   */
  n: number;

  /**
   * Size of the images to generate.
   * Must have the format `{width}x{height}`.
   * `undefined` will use the provider's default size.
   */
  size: `${number}x${number}` | undefined;

  /**
   * Aspect ratio of the images to generate.
   * Must have the format `{width}:{height}`.
   * `undefined` will use the provider's default aspect ratio.
   */
  aspectRatio: `${number}:${number}` | undefined;

  /**
   * Seed for the image generation.
   * `undefined` will use the provider's default seed.
   */
  seed: number | undefined;

  /**
   * Array of images for image editing or variation generation.
   * The images should be provided as base64 encoded strings or binary data.
   */
  files: ImageModelV3File[] | undefined;

  /**
   * Mask image for inpainting operations.
   * The mask should be provided as base64 encoded strings or binary data.
   */
  mask: ImageModelV3File | undefined;

  /**
   * Additional provider-specific options that are passed through to the provider
   * as body parameters.
   *
   * The outer record is keyed by the provider name, and the inner
   * record is keyed by the provider-specific metadata key.
   *
   * ```ts
   * {
   *   "openai": {
   *     "style": "vivid"
   *   }
   * }
   * ```
   */
  providerOptions: SharedV3ProviderOptions;

  /**
   * Abort signal for cancelling the operation.
   */
  abortSignal?: AbortSignal;

  /**
   * Additional HTTP headers to be sent with the request.
   * Only applicable for HTTP-based providers.
   */
  headers?: Record<string, string | undefined>;
};

