12	export interface BlackForestLabsProviderSettings {
13	  /**
14	   * Black Forest Labs API key. Default value is taken from the `BFL_API_KEY` environment variable.
15	   */
16	  apiKey?: string;
17	
18	  /**
19	   * Base URL for the API calls. Defaults to `https://api.bfl.ai/v1`.
20	   */
21	  baseURL?: string;
22	
23	  /**
24	   * Custom headers to include in the requests.
25	   */
26	  headers?: Record<string, string>;
27	
28	  /**
29	   * Custom fetch implementation. You can use it as a middleware to intercept
30	   * requests, or to provide a custom fetch implementation for e.g. testing.
31	   */
32	  fetch?: FetchFunction;
33	
34	  /**
35	   * Poll interval in milliseconds between status checks. Defaults to 500ms.
36	   */
37	  pollIntervalMillis?: number;
38	
39	  /**
40	   * Overall timeout in milliseconds for polling before giving up. Defaults to 60s.
41	   */
42	  pollTimeoutMillis?: number;
43	}
44	
45	export interface BlackForestLabsProvider extends ProviderV3 {
46	  /**
47	   * Creates a model for image generation.
48	   */
49	  image(modelId: BlackForestLabsImageModelId): ImageModelV3;
50	
51	  /**
52	   * Creates a model for image generation.
53	   */
54	  imageModel(modelId: BlackForestLabsImageModelId): ImageModelV3;
55	
56	  /**
57	   * @deprecated Use `embeddingModel` instead.
58	   */
59	  textEmbeddingModel(modelId: string): never;
60	}
