import { createTestServer } from '@ai-sdk/test-server/with-vitest';
import { describe, expect, it } from 'vitest';
import { createPixelArt } from './pixelart-provider';

const server = createTestServer({
  'https://api.example.com/v1/generate': {
    response: {
      type: 'json-value',
      body: {
        images: [
          {
            base64: btoa('test-image-binary'),
            seed: 42,
            style: 'pixel',
            pixelDensity: 2,
          },
        ],
      },
    },
  },
});

describe('PixelArt provider', () => {
  it('creates image models via .image and .imageModel', () => {
    const provider = createPixelArt();

    const imageModel = provider.image('pixelart-standard');
    const imageModel2 = provider.imageModel('pixelart-hd');

    expect(imageModel.provider).toBe('pixelart.image');
    expect(imageModel.modelId).toBe('pixelart-standard');
    expect(imageModel2.modelId).toBe('pixelart-hd');
    expect(imageModel.specificationVersion).toBe('v3');
  });

  it('configures baseURL and headers correctly', async () => {
    const provider = createPixelArt({
      apiKey: 'test-api-key',
      baseURL: 'https://api.example.com/v1',
      headers: {
        'x-extra-header': 'extra',
      },
    });

    const model = provider.image('pixelart-standard');

    await model.doGenerate({
      prompt: 'A cute pixel art cat',
      files: undefined,
      mask: undefined,
      n: 1,
      size: undefined,
      seed: undefined,
      aspectRatio: undefined,
      providerOptions: {},
    });

    expect(server.calls[0].requestUrl).toBe(
      'https://api.example.com/v1/generate',
    );
    expect(server.calls[0].requestMethod).toBe('POST');
    expect(server.calls[0].requestHeaders['authorization']).toBe(
      'Bearer test-api-key',
    );
    expect(server.calls[0].requestHeaders['x-extra-header']).toBe('extra');
    expect(await server.calls[0].requestBodyJson).toMatchObject({
      prompt: 'A cute pixel art cat',
      model: 'pixelart-standard',
      n: 1,
    });

    expect(server.calls[0].requestUserAgent).toContain('ai-sdk/pixelart/');
  });

  it('throws NoSuchModelError for unsupported model types', () => {
    const provider = createPixelArt();

    expect(() => provider.languageModel('some-id')).toThrowError(
      'No such languageModel',
    );
    expect(() => provider.embeddingModel('some-id')).toThrowError(
      'No such embeddingModel',
    );
  });
});

