import { FetchFunction } from '@ai-sdk/provider-utils';
import { createTestServer } from '@ai-sdk/test-server/with-vitest';
import { describe, expect, it } from 'vitest';
import { PixelArtImageModel } from './pixelart-image-model';

const prompt = 'A cute pixel art cat';

function createBasicModel({
  headers,
  fetch,
  currentDate,
}: {
  headers?: () => Record<string, string | undefined>;
  fetch?: FetchFunction;
  currentDate?: () => Date;
} = {}) {
  return new PixelArtImageModel('test-model', {
    provider: 'pixelart.image',
    baseURL: 'https://api.example.com/v1',
    headers: headers ?? (() => ({ Authorization: 'Bearer test-key' })),
    fetch,
    _internal: {
      currentDate,
    },
  });
}

describe('PixelArtImageModel', () => {
  const server = createTestServer({
    'https://api.example.com/v1/generate': {
      response: {
        type: 'json-value',
        body: {
          images: [
            {
              base64: btoa('test-binary-content'),
              seed: 42,
              style: 'pixel',
              pixelDensity: 2,
            },
          ],
        },
      },
    },
  });

  describe('doGenerate', () => {
    it('passes the correct parameters including providerOptions', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: '256x256',
        aspectRatio: undefined,
        seed: 123,
        providerOptions: {
          pixelart: {
            style: 'retro',
            pixelDensity: 3,
          },
        },
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        prompt,
        n: 1,
        model: 'test-model',
        size: '256x256',
        seed: 123,
        style: 'retro',
        pixel_density: 3,
      });
    });

    it('sends only required fields when optional fields are not provided', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        prompt,
        n: 1,
        model: 'test-model',
      });
    });

    it('returns decoded image bytes', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        seed: undefined,
        aspectRatio: undefined,
        providerOptions: {},
      });

      expect(result.images).toHaveLength(1);
      expect(result.images[0]).toBeInstanceOf(Uint8Array);
    });

    it('returns multiple images when n > 1', async () => {
      server.urls['https://api.example.com/v1/generate'].response = {
        type: 'json-value',
        body: {
          images: [
            { base64: btoa('image-1'), seed: 1 },
            { base64: btoa('image-2'), seed: 2 },
          ],
        },
      };

      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 2,
        size: undefined,
        seed: undefined,
        aspectRatio: undefined,
        providerOptions: {},
      });

      expect(result.images).toHaveLength(2);
      expect(result.images[0]).toBeInstanceOf(Uint8Array);
      expect(result.images[1]).toBeInstanceOf(Uint8Array);
    });

    it('includes seed and style in providerMetadata when provided by API', async () => {
      server.urls['https://api.example.com/v1/generate'].response = {
        type: 'json-value',
        body: {
          images: [
            {
              base64: btoa('test-binary-content'),
              seed: 42,
              style: '8bit',
              pixelDensity: 2,
            },
          ],
        },
      };

      const model = createBasicModel();
      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        seed: undefined,
        aspectRatio: undefined,
        providerOptions: {},
      });

      expect(result.providerMetadata?.pixelart.images[0]).toMatchObject({
        seed: 42,
        style: '8bit',
        pixelDensity: 2,
      });
    });

    it('omits optional fields from providerMetadata when not provided by API', async () => {
      server.urls['https://api.example.com/v1/generate'].response = {
        type: 'json-value',
        body: {
          images: [
            {
              base64: btoa('test-binary-content'),
            },
          ],
        },
      };

      const model = createBasicModel();
      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        seed: undefined,
        aspectRatio: undefined,
        providerOptions: {},
      });

      const metadata = result.providerMetadata?.pixelart.images[0];
      expect(metadata).toBeDefined();
      expect(metadata).not.toHaveProperty('seed');
      expect(metadata).not.toHaveProperty('style');
      expect(metadata).not.toHaveProperty('pixelDensity');
    });

    it('warns when aspectRatio is provided', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        seed: undefined,
        aspectRatio: '16:9',
        providerOptions: {},
      });

      expect(result.warnings).toEqual([
        {
          type: 'unsupported',
          feature: 'aspectRatio',
          details:
            'PixelArt does not support aspectRatio. Use the size parameter or width/height provider options instead.',
        },
      ]);
    });

    it('sends request to the correct URL', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        seed: undefined,
        aspectRatio: undefined,
        providerOptions: {},
      });

      expect(server.calls[0].requestMethod).toBe('POST');
      expect(server.calls[0].requestUrl).toBe(
        'https://api.example.com/v1/generate',
      );
    });

    it('merges provider and request headers', async () => {
      const modelWithHeaders = createBasicModel({
        headers: () => ({
          'Custom-Provider-Header': 'provider-header-value',
          Authorization: 'Bearer test-key',
        }),
      });

      await modelWithHeaders.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        providerOptions: {},
        headers: {
          'Custom-Request-Header': 'request-header-value',
        },
        size: undefined,
        seed: undefined,
        aspectRatio: undefined,
      });

      expect(server.calls[0].requestHeaders).toStrictEqual({
        'content-type': 'application/json',
        'custom-provider-header': 'provider-header-value',
        'custom-request-header': 'request-header-value',
        authorization: 'Bearer test-key',
      });
    });

    it('handles API errors', async () => {
      server.urls['https://api.example.com/v1/generate'].response = {
        type: 'error',
        status: 400,
        body: JSON.stringify({
          error: {
            message: 'Invalid prompt',
            code: 'invalid_request',
          },
        }),
      };

      const model = createBasicModel();

      await expect(
        model.doGenerate({
          prompt,
          files: undefined,
          mask: undefined,
          n: 1,
          providerOptions: {},
          size: undefined,
          seed: undefined,
          aspectRatio: undefined,
        }),
      ).rejects.toMatchObject({
        message: 'Invalid prompt',
        statusCode: 400,
        url: 'https://api.example.com/v1/generate',
      });
    });

    it('includes timestamp, headers, and modelId in response metadata', async () => {
      server.urls['https://api.example.com/v1/generate'].response = {
        type: 'json-value',
        body: {
          images: [{ base64: btoa('test') }],
        },
      };

      const testDate = new Date('2025-01-01T00:00:00Z');
      const model = createBasicModel({
        currentDate: () => testDate,
      });

      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        providerOptions: {},
        size: undefined,
        seed: undefined,
        aspectRatio: undefined,
      });

      expect(result.response).toStrictEqual({
        timestamp: testDate,
        modelId: 'test-model',
        headers: expect.any(Object),
      });
    });
  });

  describe('constructor', () => {
    it('exposes correct provider and model information', () => {
      const model = createBasicModel();

      expect(model.provider).toBe('pixelart.image');
      expect(model.modelId).toBe('test-model');
      expect(model.specificationVersion).toBe('v3');
      expect(model.maxImagesPerCall).toBe(4);
    });
  });
});

